// Stage tilemaps for Ghosts 'n Moore, stored as compact strings.
// Generated by a build script; verified: no gap wider than 3 tiles on the
// walking path, all ladders reachable, checkpoints/chests on solid ground.
// Chars: '.' empty  '#' solid  '=' platform  'H' ladder  'G' gravestone
//        '~' water (deadly)  '*' ice (solid, slippery)

export const TILE = 16;
export const T = { EMPTY: 0, SOLID: 1, PLAT: 2, LADDER: 3, GRAVE: 4, WATER: 5, ICE: 6 };

const CHAR = { '.': 0, '#': 1, '=': 2, 'H': 3, 'G': 4, '~': 5, '*': 6 };

export function parseMap(rows) {
  const h = rows.length, w = rows[0].length;
  const d = new Uint8Array(w * h);
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) d[y * w + x] = CHAR[rows[y][x]] || 0;
  }
  return { w, h, d };
}

export function tileAt(g, tx, ty) {
  if (tx < 0 || tx >= g.w) return T.SOLID; // stage edges are walls
  if (ty < 0 || ty >= g.h) return 0;
  return g.d[ty * g.w + tx];
}
export function setTile(g, tx, ty, v) {
  if (tx >= 0 && tx < g.w && ty >= 0 && ty < g.h) g.d[ty * g.w + tx] = v;
}

